"""Секция tagging: режим (пропуск / LLM), флаги вывода, провайдер, модель, доп. текст, стартовый набор тегов."""from __future__ import annotationsfrom types import SimpleNamespacefrom typing import Any# Подписи для bool в GUI (комбобокс)TAGGING_BOOL_UI_VALUES = ("Да", "Нет")# Формат тегов в YAML и в списке «Current tags» (нормализация при отправке и при разборе ответа)TAGGING_TAG_FORMAT_OPTIONS: tuple[tuple[str, str], ...] = (    ("Tag_name", "Tag_name — первая буква сегмента заглавная; аббревиатуры в ВЕРХНЕМ регистре без изменений"),    ("tag_name", "tag_name — все буквы строчные, слова через _"),)TAGGING_TAG_FORMAT_VALID: frozenset[str] = frozenset(    code for code, _ in TAGGING_TAG_FORMAT_OPTIONS)# Режим этапа: skip — не вызывать LLM; linear/parallel — создание тегов (один или несколько потоков)TAGGING_MODES = SimpleNamespace(    skip="skip",    create_document_tags_linear="create_document_tags_linear",    create_document_tags_parallel="create_document_tags_parallel",    options=(        ("skip", "Пропустить"),        ("create_document_tags_linear", "Линейная обработка"),        ("create_document_tags_parallel", "Пакетная обработка"),    ),    valid_codes=frozenset(        {            "skip",            "create_document_tags_linear",            "create_document_tags_parallel",        }    ),)TAGGING_LLM_MODES = frozenset(    {        TAGGING_MODES.create_document_tags_linear,        TAGGING_MODES.create_document_tags_parallel,    })# Подсказки под комбо «Режим» (та же схема, что MARKDOWN_MODE_DESCRIPTIONS)TAGGING_MODE_DESCRIPTIONS: dict[str, str] = {    TAGGING_MODES.skip: "Теги через LLM не создаются; документы идут дальше без изменения тегов.",    TAGGING_MODES.create_document_tags_linear: (        "При линейной обработке система обрабатывает каждый документ последовательно, получает из него новые теги "        "(если они созданы) и передаёт их дальше. Без провайдера и модели вызов не выполняется."    ),    TAGGING_MODES.create_document_tags_parallel: (        "При пакетной обработке одновременно обрабатывается несколько документов (число потоков — во вкладке «Общее», "        "обычно 4–8): это быстрее, но в тегах могут сформироваться синонимы. Без провайдера и модели вызов не выполняется."    ),}# Тексты вкладки «Теггирование» — те же имена полей, что в MARKDOWN_SETTINGS_UI, где возможноTAGGING_SETTINGS_UI = SimpleNamespace(    help_sidebar_title="Пояснения",    mode_field_label="Режим работы",    create_tags_field_label="Теггировать документы",    create_tags_field_hint=(        "Если «Нет», этап не вызывает LLM: теги и связанные поля из ответа модели не заполняются."    ),    tag_format_field_label="Формат тега",    tag_format_field_hint=(        "Как нормализовать теги при передаче модели и при записи в документ: "        "Tag_name (по умолчанию) — у каждого фрагмента через _ только первая буква заглавная, "        "сегмент целиком в ВЕРХНЕМ регистре не меняем; либо tag_name (всё строчные). "        "Пробелы в теге заменяются на подчёркивание."    ),    create_description_field_label="Краткое описание",    create_description_field_hint=(        "Если «Да», в YAML-ответе ожидается поле description — краткое описание документа (записывается в метаданные)."    ),    create_date_field_label="Определить дату",    create_date_field_hint=(        "Если «Да», в YAML-ответе ожидается поле date (YYYY-MM-DD или пустая строка) — дата документа по смыслу текста."    ),    llm_pick_model_header="Выбор модели",    llm_tune_model_header="Настройка модели",    llm_provider_hint="Провайдер LLM для тегирования документов",    llm_model_hint="Модель для чат-запросов (извлечение тегов из разметки)",    llm_reasoning_hint="Выделение токенов на размышления модели",    llm_temperature_hint="Случайность ответа (0.0 — детерминированный вывод)",    additional_instructions_label="Дополнительные инструкции",    additional_instructions_hint=(        "К системному сообщению автоматически добавляются инструкции по YAML-ответу "        "(tags; при включённых опциях выше — ещё description и/или date) и список уже известных тегов. "        "Здесь можно добавить свои уточнения поведения модели."    ),    start_tag_set_label="Стартовый набор тегов",    start_tag_set_hint=(        "Теги через запятую или по одному на строку. Будут переданы модели при разборе документов."    ),)TAGGING_HELP_ARTICLE = """Раздел «Теггирование» выполняется после этапа создания Markdown. По умолчанию — «Пакетная обработка» (нужны выбранные провайдер и модель; иначе LLM не вызывается).Режим работы:- Пропустить — LLM не вызывается; поле tags в результате не заполняется этим этапом (остаётся как после разметки).- Линейная обработка — документы по очереди; новые теги из каждого файла (если модель их создала) попадают в общий список и передаются при разборе следующих документов.- Пакетная обработка — несколько документов обрабатываются параллельно (число потоков задаётся во вкладке «Общее», обычно 4–8): быстрее, но возможны синонимы в названиях тегов.Доступность провайдеров и моделей зависит от добавленных API-ключей (как в разделе «Создание разметки»).Список чат-моделей настраивается в «Настройка моделей» на главном экране; подходят текстовые модели без обязательной поддержки изображений.Дополнительные инструкции: формат ответа (YAML с тегами) задаётся приложением; в этом поле можно дописать свои пожелания к модели.Стартовый набор тегов (при создании тегов LLM): через запятую или по строке на тег — база для списка в system.Теггировать документы — при «Нет» LLM для этого этапа не вызывается (независимо от режима работы и выбранной модели).Формат тега — Tag_name (по сегментам через _: только первая буква заглавная, сегмент из букв целиком в ВЕРХНЕМ не меняем — для аббревиатур) или tag_name (все строчные). Применяется к стартовому набору, к списку в промпте и к тегам из ответа модели; существующие теги в документе перед этапом приводятся к тому же формату.Краткое описание и дата — при «Да» в YAML-ответ добавляются поля description и/или date (см. подсказки у полей).""".strip()# Значения поля logic в payload/progress_sink (GUI и сводка этапа)TAGGING_PAYLOAD_LOGIC = SimpleNamespace(    skip="tagging_skip",    no_llm="tagging_no_llm",    create_tags_field_off="tagging_create_tags_field_off",    llm="tagging_llm",)TAGGING_DEFAULTS = SimpleNamespace(    tagging_mode=TAGGING_MODES.create_document_tags_parallel,    tag_format="Tag_name",    create_tags_field=True,    create_description_field=True,    create_date_field=False,    llm_provider="",    llm_model="",    llm_reasoning="low",    llm_temperature=0.3,    llm_additional_instructions="",    start_tag_set="",)TAGGING_KEYS = SimpleNamespace(    tagging_mode="tagging_mode",    tag_format="tag_format",    create_tags_field="create_tags_field",    create_description_field="create_description_field",    create_date_field="create_date_field",    llm_provider="llm_provider",    llm_model="llm_model",    llm_reasoning="llm_reasoning",    llm_temperature="llm_temperature",    llm_additional_instructions="llm_additional_instructions",    start_tag_set="start_tag_set",)class TaggingConfig:    """Умолчания и валидация секции tagging."""    TAGGING_TAG_FORMAT_OPTIONS = TAGGING_TAG_FORMAT_OPTIONS    TAGGING_TAG_FORMAT_VALID = TAGGING_TAG_FORMAT_VALID    TAGGING_MODES = TAGGING_MODES    TAGGING_LLM_MODES = TAGGING_LLM_MODES    TAGGING_MODE_DESCRIPTIONS = TAGGING_MODE_DESCRIPTIONS    TAGGING_SETTINGS_UI = TAGGING_SETTINGS_UI    TAGGING_HELP_ARTICLE = TAGGING_HELP_ARTICLE    TAGGING_PAYLOAD_LOGIC = TAGGING_PAYLOAD_LOGIC    TAGGING_DEFAULTS = TAGGING_DEFAULTS    TAGGING_KEYS = TAGGING_KEYS    @staticmethod    def get_default() -> dict[str, Any]:        """Возвращает словарь умолчаний для секции tagging."""        D = TAGGING_DEFAULTS        K = TAGGING_KEYS        M = TAGGING_MODES        return {            K.tagging_mode: D.tagging_mode,            K.tag_format: D.tag_format,            K.create_tags_field: D.create_tags_field,            K.create_description_field: D.create_description_field,            K.create_date_field: D.create_date_field,            K.llm_provider: D.llm_provider,            K.llm_model: D.llm_model,            K.llm_reasoning: D.llm_reasoning,            K.llm_temperature: D.llm_temperature,            K.llm_additional_instructions: D.llm_additional_instructions,            K.start_tag_set: D.start_tag_set,        }    @staticmethod    def coerce_bool(value: Any, default: bool) -> bool:        """Приведение к bool при чтении конфига (JSON, редкие строковые значения)."""        if value is None:            return default        if isinstance(value, bool):            return value        if isinstance(value, (int, float)):            if value == 1:                return True            if value == 0:                return False        if isinstance(value, str):            v = value.strip().lower()            if v in ("true", "1", "yes", "да"):                return True            if v in ("false", "0", "no", "нет"):                return False        return default    @staticmethod    def coerce_tag_format(value: Any, default: str) -> str:        if value is None:            return default        s = str(value).strip()        if s in TAGGING_TAG_FORMAT_VALID:            return s        return default    @staticmethod    def with_normalized_bools(tagging: dict[str, Any]) -> dict[str, Any]:        """Копия секции с каноническими bool по ключам create_tags_field / create_description_field / create_date_field."""        K = TAGGING_KEYS        D = TAGGING_DEFAULTS        t = dict(tagging)        t[K.create_tags_field] = TaggingConfig.coerce_bool(            t.get(K.create_tags_field), D.create_tags_field        )        t[K.create_description_field] = TaggingConfig.coerce_bool(            t.get(K.create_description_field), D.create_description_field        )        t[K.create_date_field] = TaggingConfig.coerce_bool(            t.get(K.create_date_field), D.create_date_field        )        t[K.tag_format] = TaggingConfig.coerce_tag_format(            t.get(K.tag_format), D.tag_format        )        return t    @staticmethod    def validate(data: Any) -> list[str]:        """Проверяет данные секции tagging. Возвращает список сообщений об ошибках."""        errors: list[str] = []        if not isinstance(data, dict):            errors.append("Tagging: ожидается объект (dict).")            return errors        K = TAGGING_KEYS        M = TAGGING_MODES        D = TAGGING_DEFAULTS        mode = data.get(K.tagging_mode) or D.tagging_mode        if isinstance(mode, str):            mode = mode.strip().lower()        else:            mode = ""        if mode == "create_document_tags":            mode = M.create_document_tags_linear        if mode not in M.valid_codes:            errors.append(                f"Tagging: tagging_mode должен быть один из: {', '.join(sorted(M.valid_codes))}."            )        tf = data.get(K.tag_format)        if tf is not None:            if not isinstance(tf, str) or str(tf).strip() not in TAGGING_TAG_FORMAT_VALID:                errors.append(                    f"Tagging: tag_format должен быть один из: {', '.join(sorted(TAGGING_TAG_FORMAT_VALID))}."                )        for bool_key in (K.create_tags_field, K.create_description_field, K.create_date_field):            val = data.get(bool_key)            if val is not None and not isinstance(val, bool):                errors.append(f"Tagging: поле {bool_key} должно быть true/false (bool).")        for key in (            K.llm_provider,            K.llm_model,            K.llm_reasoning,            K.llm_additional_instructions,            K.start_tag_set,        ):            val = data.get(key)            if val is not None and not isinstance(val, str):                errors.append(f"Tagging: поле {key} должно быть строкой.")        t = data.get(K.llm_temperature)        if t is not None:            try:                tf = float(t)                if not (0.0 <= tf <= 2.0):                    errors.append("Tagging: llm_temperature должен быть от 0.0 до 2.0.")            except (TypeError, ValueError):                errors.append("Tagging: llm_temperature должен быть числом.")        reason = (data.get(K.llm_reasoning) or "").strip().lower()        if reason and reason not in ("disabled", "low", "medium", "high"):            errors.append(                "Tagging: llm_reasoning должен быть один из: disabled, low, medium, high."            )        return errors